// Function to reverse a linked list
Node* reverse(Node* head) {
    Node* prev = nullptr;
    Node* curr = head;
    Node* next = nullptr;

    while (curr != nullptr) {
        next = curr->next;
        curr->next = prev;
        prev = curr;
        curr = next;
    }
    return prev;
}

// Function to add one to the number represented by linked list
Node* addOne(Node* head) {
    // Step 1: Reverse list for easier addition
    head = reverse(head);

    Node* curr = head;
    Node* prev = nullptr;
    int carry = 1; // since we are adding 1

    // Step 2: Traverse and add carry
    while (curr != nullptr) {
        int sum = curr->data + carry;
        curr->data = sum % 10;
        carry = sum / 10;
        prev = curr;
        curr = curr->next;
    }

    // Step 3: If carry remains, add new node
    if (carry > 0) {
        prev->next = new Node(carry);
    }

    // Step 4: Reverse again to restore original order
    head = reverse(head);
    return head;
}

