function addOne(head) {
    head = reverse(head);
    let curr = head;
    let carry = 1; // we need to add one
    let prev = null;

    while (curr !== null) {
        let sum = curr.data + carry;
        curr.data = sum % 10;
        carry = Math.floor(sum / 10);
        prev = curr;
        curr = curr.next;
    }

    if (carry > 0) {
        prev.next = new Node(carry);
    }

    head = reverse(head);
    return head;
}
